      'marble-roulette': { name: "구슬 룰렛", desc: "물리 시뮬레이션 기반 구슬 뽑기 게임입니다.", ui: {"badge0":"내 브라우저에서만","badge1":"공정하고 예측 불가","heading0":"보드","status0":"준비 완료.","stat0":"드롭 수","stat1":"속도","text1":"시작","text2":"초기화","heading1":"우승자","text3":"—","heading2":"공정성","desc0":"각 드롭은 Web Crypto로 시작 위치를 무작위화합니다.","heading3":"컨트롤","label0":"이름 / 옵션","placeholder0":"철수&#10;영희&#10;민수&#10;지수","desc1":"이름을 2~10개 입력하세요. (줄바꿈 또는 쉼표 구분)","label2":"속도","button0":"1배속","button1":"2배속","button2":"3배속","desc2":"속도를 높이면 시뮬레이션이 더 빨라집니다.","button3":"시작","button4":"초기화","heading4":"결과","text4":"🏁 순위","button5":"한 번 더","button6":"우승자 제거 후 다시","button7":"새 추첨","desc3":"팁: ?names=Alice,Bob&autostart=true 를 붙여 공유할 수 있습니다.","heading5":"통계","button8":"통계 초기화","text5":"아직 드롭이 없습니다 — 시작을 눌러주세요.","heading8":"우승자","text6":"가장 먼저 도착했습니다!","button9":"좋아요","labelTheme":"보드 테마","descTheme":"추첨 흐름은 그대로 두고 핀 밀도와 보드 움직임만 바꿉니다.","labelWinnerMode":"우승 기준","descWinnerMode":"가장 먼저, 가장 늦게, 또는 특정 순위를 우승자로 선택할 수 있습니다.","buttonShuffle":"섞기","themeClassic":"클래식 드롭","themeArc":"아크 스프린트","themeChaos":"카오스 퍼널","targetFirst":"가장 먼저 도착","targetLast":"가장 늦게 도착","targetOrdinal":"N번째 도착","replayLabel":"Slow-Mo Replay","buttonReplay":"Slow-Mo Replay","desc16":"' + String(m.rank) + '","desc17":"' + escapeHtml(m.name) + '","desc18":"' + escapeHtml(r.name) + '","desc19":"' + String(r.count) + '"}, js: {"text0":"—","text1":"준비 완료.","err0":"이름을 최소 2개 입력하세요.","err1":"최대 10개까지 가능합니다.","text2":"드롭 중...","text3":"아직 완주한 구슬이 없습니다.","text4":"레이스가 종료되었습니다.","text5":"우승자가 정해졌습니다!","text6":"시간 종료 — 진행률 기준으로 순위를 정합니다.","text7":"드롭 수:","err2":"우승자를 제거한 뒤 최소 2개의 이름이 필요합니다.","text8":"통계를 초기화했습니다.","textReplay":"Replaying winner path..."} }
